import { apiClient, unwrap, type BffResponse } from '../api';
import type {
  PaginatedResult,
  PurchaseRequestDto,
  PurchaseRequestFilter,
  CreatePurchaseRequestDto,
  UpdatePurchaseRequestDto,
  PurchaseOrderDto,
  PurchaseOrderFilter,
  CreatePurchaseOrderDto,
  UpdatePurchaseOrderDto,
  ReceivingNoteDto,
  ReceivingNoteFilter,
  CreateReceivingNoteDto,
  UpdateReceivingNoteDto,
  EinvoiceDto,
  EinvoiceFilter,
  ApprovalStepDto,
  PurchaseApproverDto,
} from './models';

const BASE = '/purchasing';

function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

export const purchasingEndpoint = {
  getRequests: async (filter?: PurchaseRequestFilter) => {
    const qs = buildQs({
      status: filter?.status,
      fromDate: filter?.fromDate,
      toDate: filter?.toDate,
      search: filter?.search,
      page: filter?.page ?? 1,
      pageSize: filter?.pageSize ?? 20,
    });
    const res = await apiClient.get<BffResponse<PaginatedResult<PurchaseRequestDto>>>(`${BASE}/requests?${qs}`);
    return unwrap(res);
  },

  getRequest: async (id: string) => {
    const res = await apiClient.get<BffResponse<PurchaseRequestDto>>(`${BASE}/requests/${id}`);
    return unwrap(res);
  },

  createRequest: async (dto: CreatePurchaseRequestDto) => {
    const res = await apiClient.post<BffResponse<PurchaseRequestDto>>(`${BASE}/requests`, dto);
    return unwrap(res);
  },

  updateRequest: async (id: string, dto: UpdatePurchaseRequestDto) => {
    const res = await apiClient.put<BffResponse<PurchaseRequestDto>>(`${BASE}/requests/${id}`, dto);
    return unwrap(res);
  },

  approveRequest: async (id: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/requests/${id}/approve`);
    return unwrap(res);
  },

  rejectRequest: async (id: string, reason: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/requests/${id}/reject`, reason);
    return unwrap(res);
  },

  getOrders: async (filter?: PurchaseOrderFilter) => {
    const qs = buildQs({
      supplierId: filter?.supplierId,
      status: filter?.status,
      fromDate: filter?.fromDate,
      toDate: filter?.toDate,
      search: filter?.search,
      page: filter?.page ?? 1,
      pageSize: filter?.pageSize ?? 20,
    });
    const res = await apiClient.get<BffResponse<PaginatedResult<PurchaseOrderDto>>>(`${BASE}/orders?${qs}`);
    return unwrap(res);
  },

  getOrder: async (id: string) => {
    const res = await apiClient.get<BffResponse<PurchaseOrderDto>>(`${BASE}/orders/${id}`);
    return unwrap(res);
  },

  createOrder: async (dto: CreatePurchaseOrderDto) => {
    const res = await apiClient.post<BffResponse<PurchaseOrderDto>>(`${BASE}/orders`, dto);
    return unwrap(res);
  },

  updateOrder: async (id: string, dto: UpdatePurchaseOrderDto) => {
    const res = await apiClient.put<BffResponse<PurchaseOrderDto>>(`${BASE}/orders/${id}`, dto);
    return unwrap(res);
  },

  confirmOrder: async (id: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/orders/${id}/confirm`);
    return unwrap(res);
  },

  closeOrder: async (id: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/orders/${id}/close`);
    return unwrap(res);
  },

  getReceivingNotes: async (filter?: ReceivingNoteFilter) => {
    const qs = buildQs({
      purchaseOrderId: filter?.purchaseOrderId,
      status: filter?.status,
      fromDate: filter?.fromDate,
      toDate: filter?.toDate,
      search: filter?.search,
      page: filter?.page ?? 1,
      pageSize: filter?.pageSize ?? 20,
    });
    const res = await apiClient.get<BffResponse<PaginatedResult<ReceivingNoteDto>>>(`${BASE}/receiving-notes?${qs}`);
    return unwrap(res);
  },

  getReceivingNote: async (id: string) => {
    const res = await apiClient.get<BffResponse<ReceivingNoteDto>>(`${BASE}/receiving-notes/${id}`);
    return unwrap(res);
  },

  createReceivingNote: async (dto: CreateReceivingNoteDto) => {
    const res = await apiClient.post<BffResponse<ReceivingNoteDto>>(`${BASE}/receiving-notes`, dto);
    return unwrap(res);
  },

  updateReceivingNote: async (id: string, dto: UpdateReceivingNoteDto) => {
    const res = await apiClient.put<BffResponse<ReceivingNoteDto>>(`${BASE}/receiving-notes/${id}`, dto);
    return unwrap(res);
  },

  postReceivingNote: async (id: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/receiving-notes/${id}/post`);
    return unwrap(res);
  },

  cancelReceivingNote: async (id: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/receiving-notes/${id}/cancel`);
    return unwrap(res);
  },

  getEinvoices: async (filter?: EinvoiceFilter) => {
    const qs = buildQs({
      fromDate: filter?.fromDate,
      toDate: filter?.toDate,
      status: filter?.status,
      search: filter?.search,
      page: filter?.page ?? 1,
      pageSize: filter?.pageSize ?? 20,
    });
    const res = await apiClient.get<BffResponse<PaginatedResult<EinvoiceDto>>>(`${BASE}/einvoices?${qs}`);
    return unwrap(res);
  },

  getEinvoice: async (id: string) => {
    const res = await apiClient.get<BffResponse<EinvoiceDto>>(`${BASE}/einvoices/${id}`);
    return unwrap(res);
  },

  verifyEinvoice: async (id: string) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/einvoices/${id}/verify`);
    return unwrap(res);
  },

  getApprovalFlow: async () => {
    try {
      const res = await apiClient.get<BffResponse<ApprovalStepDto[]>>(`${BASE}/approval-flow`);
      const data = unwrap(res);
      return Array.isArray(data) ? data : [];
    } catch {
      return [] as ApprovalStepDto[];
    }
  },

  saveApprovalFlow: async (steps: ApprovalStepDto[]) => {
    const res = await apiClient.put<BffResponse<ApprovalStepDto[]>>(`${BASE}/approval-flow`, steps);
    return unwrap(res);
  },

  getApprovers: async () => {
    try {
      const res = await apiClient.get<BffResponse<PurchaseApproverDto[]>>(`${BASE}/approvers`);
      const data = unwrap(res);
      return Array.isArray(data) ? data : [];
    } catch {
      return [] as PurchaseApproverDto[];
    }
  },

  saveApprovers: async (approvers: PurchaseApproverDto[]) => {
    const res = await apiClient.put<BffResponse<PurchaseApproverDto[]>>(`${BASE}/approvers`, approvers);
    return unwrap(res);
  },
};
